import React from 'react';
import { useDispatch } from 'react-redux';
import { deleteSchedule } from '../redux/slices/rasps';

export const Rasp = ({
  id,
  time,
  day,
  predmet,
  group,
  teacher,
  kurs,
  room,
  user,
  isLoading,
  isEditable,
}) => {
  const dispatch = useDispatch();

  const handleRemoveRasp = async () => {
    try {
      // Rasp silme işlemi
      await dispatch(deleteSchedule(id));
      console.log('Rasp başarıyla silindi!');
    } catch (error) {
      console.error('Rasp silme işlemi başarısız oldu:', error);
    }
  };

  if (isLoading) {
    // Yükleme durumu göster
    return <p>Loading...</p>;
  }

  return (
    <div className="bg-white px-4 pt-3 pb-4 rounded-sm border border-gray-200 flex-1">
      <strong className="text-gray-700 font-medium">Расписания</strong>
      <div className="border-x border-gray-200 rounded-sm mt-3">
        <table className="w-full text-gray-700">
          <thead>
            <tr>
              <th>Время</th>
              <th>День</th>
              <th>Предмет</th>
              <th>Группа</th>
              <th>Преподаватель</th>
              <th>Курс</th>
              <th>Кабинет</th>
              {isEditable && <th>Actions</th>}
            </tr>
          </thead>
          <tbody>
            <tr>
              <td>{time}</td>
              <td>{day}</td>
              <td>{predmet}</td>
              <td>{group}</td>
              <td>{teacher}</td>
              <td>{kurs}</td>
              <td>{room}</td>
              {isEditable && (
                <td>
                  <button onClick={handleRemoveRasp}>Remove</button>
                </td>
              )}
            </tr>
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default Rasp;
